           Y := substitute(Z, QQ);     B := substitute(H, QQ);   
           if rank source B > 0 then Y = Y | B | -B;
           n := rank source Y;         d := rank target Y;     
           A := Y | -id_(QQ^d);
           -- computing the row echelon form of 'A'
           A = gens gb rotateMatrix A;
           L := rotateMatrix leadTerm A;
